from flask import Flask, request, Response
from prometheus_client import Counter, generate_latest, CONTENT_TYPE_LATEST, CollectorRegistry, multiprocess
import time

app = Flask(__name__)

REQUESTS = Counter(
    "http_requests_total",
    "Total HTTP requests",
    ["user_id", "session_id", "path"],
)

@app.before_request
def start_timer():
    request._start_time = time.time()

@app.after_request
def record_metrics(response):
    user_id = request.headers.get("X-User-Id", "unknown")
    session_id = request.headers.get("X-Session-Id", "unknown")
    path = request.full_path if request.full_path else request.path
    REQUESTS.labels(user_id=user_id, session_id=session_id, path=path).inc()
    return response

@app.route("/")
def index():
    return "ok"

@app.route("/metrics")
def metrics():
    registry = CollectorRegistry()
    multiprocess.MultiProcessCollector(registry)
    return Response(generate_latest(registry), mimetype=CONTENT_TYPE_LATEST)

@app.route("/hello/<name>")
def hello(name):
    return f"hello {name}"

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8000)